B.Nl=new A.K(B.a8,"Modals express obligation and permission",'Modal verbs are essential in aviation English because they express **degrees of obligation**. The difference between "must" and "should" can have safety implications.\n\n**must** = mandatory (regulatory requirement)\n**should** = recommended (best practice)\n**may** = permitted (allowed)\n**can** = ability / theoretical possibility',null,null,null)
B.Pk=new A.K(B.eN,"Modal strength spectrum",null,null,B.q9,null)
B.Nd=new A.K(B.B,"Modal + Verb Structure",'**Rule:** Modal verb + **base infinitive** (no "to", no "-s", no "-ing")\n\n\u2713 The pilot **must check** the fuel level.\n\u2717 The pilot must **checks** / must **checking** / must **to check**\n\n**With passive:**\nModal + **be** + past participle\n\u2713 The engine **must be shut down** before maintenance.\n\u2713 Parts **should be inspected** visually.',null,null,null)
B.IL=new A.az("The engine must be shut down before any maintenance work begins.","Herhangi bir bak\u0131m \xe7al\u0131\u015fmas\u0131 ba\u015flamadan \xf6nce motor kapat\u0131lmal\u0131d\u0131r.","must be shut down")
B.JS=new A.az("Technicians should wear protective equipment when handling fuel.","Teknisyenler yak\u0131t ile \xe7al\u0131\u015f\u0131rken koruyucu ekipman takmal\u0131d\u0131r.","should wear")
B.Jj=new A.az("The aircraft may depart after all checks are completed.","T\xfcm kontroller tamamland\u0131ktan sonra u\xe7ak kalkabilir.","may depart")
B.Jg=new A.az("Contaminated parts must not be reinstalled without inspection.","Kirlenmi\u015f par\xe7alar incelenmeden yeniden tak\u0131lmamal\u0131d\u0131r.","must not be reinstalled")
B.Sg=s([B.IL,B.JS,B.Jj,B.Jg],t.l)
B.Of=new A.K(B.a9,"Modals in Context",null,B.Sg,null,null)
B.N7=new A.K(B.aa,"\u2708\ufe0f Exam Tip",'Common distractors in modal questions:\n\u2022 "must checking" \u2192 WRONG (modal + base form, not -ing)\n\u2022 "should to inspect" \u2192 WRONG (no "to" after modals)\n\u2022 "must performed" \u2192 WRONG (passive needs "be": must **be** performed)\n\nIf you see a modal verb + gap, check: is an active or passive meaning needed?',null,null,null)
