B.O3=new A.K(B.a8,"ATC phraseology is standardized","Air Traffic Control communications follow ICAO standard phraseology. Fill-in-the-blank questions test whether you know the **exact words** used in clearances, instructions, and readbacks.\n\nThe key is understanding the **structure** of each phrase type so you can identify the missing word even without memorizing every phrase.",null,null,null)
B.Pc=new A.K(B.B,"\ud83d\udeeb Clearance Structure",'A standard ATC clearance follows this pattern:\n\n**Aircraft ID** + clearance limit + route + altitude + speed + squawk\n\nExample: "THY123, **cleared to** Istanbul, via KEMER, **climb and maintain** FL350, squawk 4521."\n\nKey verbs: **cleared**, **maintain**, **climb**, **descend**, **turn**, **contact**, **report**',null,null,null)
B.N3=new A.K(B.B,"\ud83d\udcfb Readback Rules",'Pilots must **read back** all:\n\u2022 Runway in use\n\u2022 Altimeter settings\n\u2022 Altitude/flight level\n\u2022 Heading instructions\n\u2022 Speed instructions\n\u2022 Frequency changes\n\u2022 Transponder codes\n\u2022 Taxi instructions (at controlled airports)\n\n**Standard phrase:** "Cleared to FL350, THY123." (call sign at end in readback)',null,null,null)
B.Jc=new A.az(u.G,"THY123, al\xe7al ve u\xe7u\u015f seviyesi 150'yi koru.","descend and maintain")
B.JJ=new A.az("Cleared for ILS approach runway 36R, report established.","\u0130LS yakla\u015f\u0131m\u0131 pist 36R i\xe7in yetkilendirildiniz, ini\u015f glide slope'unda oldu\u011funuzda bildirin.","report established")
B.JT=new A.az("Hold short of runway 18L, traffic on final.","Pist 18L'ye girmeden bekleyin, finalden gelen trafik var.","Hold short")
