B.MR=new A.K(B.a8,"Checklists follow fixed language patterns","Aviation checklists use a highly standardized language structure. Unlike conversational English, checklist language is **compressed and precise** \u2014 each word is chosen for accuracy and brevity.\n\nFill-in-the-blank questions test whether you know the correct technical term or phrase for each checklist item.",null,null,null)
B.MB=new A.K(B.B,"\ud83d\udccb Checklist Language Patterns",'Checklists use three main patterns:\n\n**Challenge / Response:**\n"PARKING BRAKE \u2014 **SET**"\n"SEAT BELTS \u2014 **ON**"\n"FUEL QUANTITY \u2014 **CHECKED**"\n\n**Action items:**\n"\u2026\u2026\u2026 the altimeters to QNH"\n"\u2026\u2026\u2026 the ILS frequency and course"\n"\u2026\u2026\u2026 the transponder to 2000"\n\nCommon action verbs: **set, check, confirm, select, arm, position, verify, engage**',null,null,null)
B.J8=new A.az("Set the altimeter to the current QNH of 1013 hectopascals.","Altimetreyi mevcut QNH de\u011feri olan 1013 hektopaskal'a ayarlay\u0131n.","Set")
B.IQ=new A.az("Arm the ground spoilers and confirm flap setting for takeoff.","Yer frenlerini aktif konuma getirin ve kalk\u0131\u015f i\xe7in flap ayar\u0131n\u0131 do\u011frulay\u0131n.","Arm")
B.IG=new A.az("Verify that all doors are closed and armed before pushback.","Geri itme \xf6ncesinde t\xfcm kap\u0131lar\u0131n kapal\u0131 ve kilitlendi\u011fini do\u011frulay\u0131n.","Verify")
