B.MP=new A.K(B.a8,"Conditionals describe cause and effect","Aviation procedures often describe what happens **if** a certain condition occurs. Emergency checklists, operational manuals, and exam questions rely heavily on conditional sentences.\n\nUnderstanding which conditional type to use depends on whether the situation is **real/possible** or **hypothetical/impossible**.",null,null,null)
B.OL=new A.K(B.eN,"Conditional types at a glance",null,null,B.qa,null)
B.MS=new A.K(B.B,"The Three Main Types",'**Type 1 \u2014 Real/Possible (present/future)**\nIf + present simple, will/can/must + base verb\n\u2192 "If the oil pressure drops, the pilot **will** declare an emergency."\n\n**Type 2 \u2014 Hypothetical (present/future)**\nIf + past simple, would/could + base verb\n\u2192 "If the engine **failed**, the crew **would** follow the ECAM."\n\n**Type 3 \u2014 Impossible (past)**\nIf + past perfect, would/could + have + past participle\n\u2192 "If the crew **had noticed** the leak, they **would have** diverted."',null,null,null)
B.IF=new A.az("If the fuel quantity drops below minimum, the aircraft must return to base.","Yak\u0131t miktar\u0131 minimumun alt\u0131na d\xfc\u015ferse u\xe7ak \xfcsse d\xf6nmelidir.","If the fuel quantity drops")
B.JD=new A.az("If the hydraulic system were to fail, the pilot would use backup controls.","Hidrolik sistem ar\u0131za yapsa pilot yedek kontrolleri kullan\u0131rd\u0131.","were to fail")
B.IC=new A.az("If maintenance had been performed on time, the fault would not have occurred.","Bak\u0131m zaman\u0131nda yap\u0131lsayd\u0131 ar\u0131za meydana gelmezdi.","had been performed")
B.UC=s([B.IF,B.JD,B.IC],t.l)
B.Ow=new A.K(B.a9,"Aviation Conditionals",null,B.UC,null,null)
B.Pj=new A.K(B.aa,"\u2708\ufe0f Exam Tip",'Quick identification trick:\n\u2022 See "will" in the result clause \u2192 **Type 1** (real)\n\u2022 See "would" + present base \u2192 **Type 2** (hypothetical)\n\u2022 See "would have" + past participle \u2192 **Type 3** (past)\n\nWatch for "unless" = "if not":\n"Unless the checklist is completed, departure is not permitted."\n= "If the checklist is **not** completed, departure is not permitted."',null,null,null)
B.TZ=s(["will drop","drops","dropped","would drop"],t.s)
B.a0_=new A.a5(-40,B.af,100,"If the oil pressure \u2026\u2026\u2026\u2026 below the minimum, the pilot must shut down the engine.",B.TZ,1,B.z,null,null,null)
