B.RX=s([B.JK,B.J_,B.JN],t.l)
B.O_=new A.K(B.a9,"METAR Example",null,B.RX,null,null)
B.NQ=new A.K(B.aa,"\u2708\ufe0f Exam Tip",'METAR reading order (always the same):\nStation \u2192 Date/Time \u2192 Wind \u2192 Visibility \u2192 Weather \u2192 Cloud \u2192 Temperature/Dewpoint \u2192 QNH \u2192 Trend\n\n"QNH" vs "QFE":\n\u2022 **QNH** \u2192 altitude above sea level (standard, used for en-route)\n\u2022 **QFE** \u2192 altitude above aerodrome (shows 0 when on ground)\n\nMost exam questions ask about QNH.',null,null,null)
B.RH=s(["Ceiling above visibility OK","Ceiling and visibility are satisfactory with no significant weather","Clouds are visible at low altitude","Clear air visibility over 5km"],t.s)
