B.a_X=new A.a5(-272,B.ar,642,'"Expect vectors" on a STAR means:',B.V8,1,B.aU,null,null,null)
B.Rw=s(["Climb to speed 220 knots","Maintain 220 KIAS or less","Set Mach 0.220","Not exceed 220 feet per minute climb"],t.s)
B.a_t=new A.a5(-273,B.ar,643,'If a SID shows "S220" at a waypoint, the crew must:',B.Rw,1,B.aU,null,null,null)
